<template><view class="page"><view class="title">庆喜儿商城</view><AppCard v-for="x in items" :key="x.id" :title="x.name"><view>¥{{x.price}} · 库存 {{x.stock}}</view><button class="btn" @click="buy(x)">购买</button></AppCard></view></template><script setup lang="ts">import{ref}from'vue';import{onShow}from'@dcloudio/uni-app';import AppCard from'@/components/AppCard.vue';import{qingxierApi}from'@/services/api';const items=ref<any[]>([]);onShow(async()=>items.value=(await qingxierApi.products()).filter(x=>x.type!=='reward'));async function buy(x:any){uni.showModal({title:'提示',content:'请先在个人中心维护收货地址',showCancel:false})}</script>
